class Piece:
    def __init__(self, color):
        self.color = color

class Board:
    def __init__(self):
        self._board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self._board[row][col] = Piece("white")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self._board[row][col] = Piece("black")

    def get_piece(self, row, col):
        return self._board[row][col]

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece is not None:
            self._board[end_row][end_col] = piece
            self._board[start_row][start_col] = None

    def __str__(self):
        result = "  a b c d e f g h\n"
        for row in range(8):
            result += str(row + 1) + " "
            for col in range(8):
                piece = self.get_piece(row, col)
                if piece is None:
                    result += ". "
                elif piece.color == "white":
                    result += "W "
                else:
                    result += "B "
            result += "\n"
        return result
```

